// HIER DEINE SPORT-PROJEKT-ID EINTRAGEN
const sportProjectId = 0;

if (!sportProjectId) {
  return [{ json: { error: 'SPORT_PROJECT_ID_MISSING', hint: 'Bitte im Node "Code - Sport Projekt-ID" die Sport-Projekt-ID eintragen.' } }];
}

return [{ json: { project_id: String(sportProjectId) } }];

// ==========================================================
// SPORT AUTO-COMPLETE LOGIK v2
// Strava = Laufen/Cardio draußen
// Hevy = Gym/Home-Workouts
//
// Ziel:
// - Wochenziel: 3 Workouts pro Woche
// - Strava-Aktivitäten zählen als Cardio/Laufen
// - Hevy-Workouts zählen als Gym/Home
// - Wenn heute ein Workout erkannt wurde: heutige/offene Sport-Aufgabe abhaken
// - Wenn diese Woche schon 3 Workouts erkannt wurden: offene Sport-Aufgabe abhaken
// ==========================================================

function startOfWeek(d) {
  const x = new Date(d);
  const day = x.getDay(); // 0 Sunday
  const diff = (day === 0 ? -6 : 1 - day);
  x.setDate(x.getDate() + diff);
  x.setHours(0,0,0,0);
  return x;
}

function ymd(date) {
  if (!date) return '';
  return new Date(date).toISOString().slice(0, 10);
}

function parseStrava(input) {
  const arr = Array.isArray(input) ? input : (input.data || input.activities || []);
  const allowedTypes = [
    'Run',
    'TrailRun',
    'VirtualRun',
    'Walk',
    'Hike',
    'Ride',
    'VirtualRide',
    'Workout'
  ];

  return arr
    .filter(a => a && (a.start_date || a.start_date_local))
    .filter(a => allowedTypes.includes(a.type || a.sport_type || ''))
    .map(a => ({
      source: 'strava',
      kind: 'cardio',
      name: a.name || `${a.type || a.sport_type || 'Strava'} Aktivität`,
      type: a.type || a.sport_type || 'unknown',
      date: a.start_date_local || a.start_date,
      duration_seconds: a.elapsed_time || a.moving_time || 0,
      distance_m: a.distance || 0
    }));
}

function parseHevy(input) {
  // Hevy liefert je nach Endpoint z.B. {workouts:[...]} oder {data:[...]}
  const arr = Array.isArray(input) ? input : (input.workouts || input.data || input.events || []);
  return arr
    .map(w => w.workout || w)
    .filter(w => w && (w.start_time || w.created_at || w.updated_at || w.date))
    .map(w => ({
      source: 'hevy',
      kind: 'strength',
      name: w.title || w.name || 'Hevy Workout',
      type: 'gym_home',
      date: w.start_time || w.created_at || w.updated_at || w.date,
      duration_seconds: w.duration_seconds || w.duration || 0,
      exercise_count: Array.isArray(w.exercises) ? w.exercises.length : null
    }));
}

function extractTasks(input) {
  const maybe = input.data || input.tasks || input.results || input;
  if (!Array.isArray(maybe)) return [];
  if (!maybe.some(x => x && x.title && ('done' in x || 'due_date' in x || 'id' in x))) return [];
  return maybe;
}

const now = new Date();
const weekStart = startOfWeek(now);
const todayYmd = ymd(now);

const inputs = $input.all().map(i => i.json);
let vikunjaTasks = [];
let workouts = [];

for (const inp of inputs) {
  const tasks = extractTasks(inp);
  if (tasks.length) {
    vikunjaTasks = tasks;
    continue;
  }

  // Heuristik: Strava Aktivitäten haben oft "type"/"sport_type"; Hevy Workouts "exercises"/"title"
  const rawArr = Array.isArray(inp) ? inp : (inp.data || inp.workouts || inp.activities || inp.events || []);
  if (Array.isArray(rawArr) && rawArr.some(x => x && (x.type || x.sport_type || x.distance))) {
    workouts.push(...parseStrava(inp));
  } else {
    workouts.push(...parseHevy(inp));
  }
}

// Dedupe grob nach Quelle+Datum+Name
const seen = new Set();
workouts = workouts.filter(w => {
  const key = `${w.source}|${w.date}|${w.name}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

const weekWorkouts = workouts.filter(w => new Date(w.date) >= weekStart);
const todayWorkouts = workouts.filter(w => ymd(w.date) === todayYmd);

const stravaWeek = weekWorkouts.filter(w => w.source === 'strava');
const hevyWeek = weekWorkouts.filter(w => w.source === 'hevy');

const openSportTasks = vikunjaTasks
  .filter(t => !t.done)
  .filter(t => `${t.title || ''} ${t.description || ''}`.toLowerCase().includes('sport'))
  .sort((a,b) => new Date(a.due_date || 0) - new Date(b.due_date || 0));

const dueOrTodaySportTasks = openSportTasks.filter(t => {
  if (!t.due_date) return true;
  return new Date(t.due_date) <= now;
});

const results = [];

if (todayWorkouts.length > 0 && dueOrTodaySportTasks.length > 0) {
  const task = dueOrTodaySportTasks[0];
  const details = todayWorkouts.map(w => `${w.source.toUpperCase()}: ${w.name}`).join(', ');
  results.push({
    json: {
      action: 'complete_task',
      task_id: task.id,
      title: task.title,
      done: true,
      reason: `Heute Workout erkannt: ${details}`,
      workout_count_week: weekWorkouts.length,
      strava_count_week: stravaWeek.length,
      hevy_count_week: hevyWeek.length
    }
  });
} else if (weekWorkouts.length >= 3 && openSportTasks.length > 0) {
  const task = openSportTasks[0];
  results.push({
    json: {
      action: 'complete_task',
      task_id: task.id,
      title: task.title,
      done: true,
      reason: `Wochenziel 3x Sport erreicht: ${weekWorkouts.length}/3 Workouts (${stravaWeek.length} Strava, ${hevyWeek.length} Hevy).`,
      workout_count_week: weekWorkouts.length,
      strava_count_week: stravaWeek.length,
      hevy_count_week: hevyWeek.length
    }
  });
} else {
  const remaining = Math.max(0, 3 - weekWorkouts.length);
  results.push({
    json: {
      action: 'notify',
      workout_count_week: weekWorkouts.length,
      strava_count_week: stravaWeek.length,
      hevy_count_week: hevyWeek.length,
      workout_count_today: todayWorkouts.length,
      message:
`🏃‍♂️ Sport-Status diese Woche: ${weekWorkouts.length}/3

Strava/Laufen/Cardio: ${stravaWeek.length}
Hevy/Gym/Home: ${hevyWeek.length}

Noch offen: ${remaining} Workout(s).
Wenn heute nichts mehr geht: Sportaufgabe im Abend-Review verschieben.`
    }
  });
}

return results;

const config = $('Konfiguration1').first().json;

// Diese Projekte werden angelegt. "Heute" ist bewusst NICHT enthalten.
const wantedProjects = [
  { key: 'INBOX', name: 'Inbox', description: 'Sammelstelle für neue ungeplante Aufgaben.' },
  { key: 'TERMINE', name: 'Termine', description: 'Aufgaben mit festen Terminen, Fristen und Erinnerungen.' },
  { key: 'MENSCHEN', name: 'Menschen', description: 'Rückmeldungen, Anrufe, Kontakte und soziale Verpflichtungen.' },
  { key: 'HAUSHALT', name: 'Haushalt', description: 'Allgemeine Haushaltsaufgaben.' },
  { key: 'PUTZEN', name: 'Putzen', description: 'Reinigung: Bad, saugen, wischen, Schreibtisch, Waschmaschine reinigen.' },
  { key: 'EINKAUFEN', name: 'Einkaufen', description: 'Einkaufslisten, Besorgungen und Dinge, die gekauft werden müssen.' },
  { key: 'SPORT', name: 'Sport', description: 'Gym, Home Workouts, Strava, Hevy und Bewegung.' },
  { key: 'FINANZEN', name: 'Finanzen', description: 'Rechnungen, Zahlungen, Firefly, Verträge und Geldthemen.' },
  { key: 'PAPIERKRAM', name: 'Papierkram', description: 'Dokumente, Behörden, Versicherungen und Ablage.' },
  { key: 'DIGITAL', name: 'Digital', description: 'IT, Homelab, Accounts, Automationen und digitale Ordnung.' },
  { key: 'AUTO', name: 'Auto', description: 'KFZ, Steuer, Versicherung, Werkstatt, TÜV und Wartung.' },
  { key: 'SICHERHEIT', name: 'Sicherheit', description: 'Backups, Passwörter, Updates, Notfall- und Sicherheitsaufgaben.' }
];

const existing = items.map(i => i.json);
const existingTitles = new Set(
  existing
    .map(p => String(p.title || p.name || '').trim().toLowerCase())
    .filter(Boolean)
);

const missing = wantedProjects
  .filter(p => !existingTitles.has(p.name.toLowerCase()))
  .map(p => ({
    json: {
      key: p.key,
      title: p.name,
      description: p.description,
      vikunja_url: config.vikunja_url,
      vikunja_token: config.vikunja_token,
      action: 'create'
    }
  }));

const alreadyThere = wantedProjects
  .filter(p => existingTitles.has(p.name.toLowerCase()))
  .map(p => {
    const found = existing.find(e => String(e.title || e.name || '').trim().toLowerCase() === p.name.toLowerCase());
    return {
      json: {
        key: p.key,
        title: p.name,
        id: found?.id,
        action: 'exists'
      }
    };
  });

if (missing.length === 0) {
  return [{
    json: {
      nothing_to_create: true,
      message: 'Alle benötigten Projekte existieren bereits.',
      existing_projects: alreadyThere.map(i => ({ key: i.json.key, title: i.json.title, id: i.json.id }))
    }
  }];
}

return missing;

return items.map(item => {
  return {
    json: {
      status: 'angelegt',
      project_id: item.json.id,
      title: item.json.title,
      env_name: 'VIKUNJA_PROJECT_' + String(item.json.title || '')
        .toUpperCase()
        .replace(/Ä/g, 'AE')
        .replace(/Ö/g, 'OE')
        .replace(/Ü/g, 'UE')
        .replace(/ß/g, 'SS')
        .replace(/[^A-Z0-9]+/g, '_')
        .replace(/^_|_$/g, '') + '_ID'
    }
  };
});

const data = $json;
return [{
  json: {
    status: 'nichts_zu_tun',
    message: data.message || 'Alle Projekte existieren bereits.',
    existing_projects: data.existing_projects || []
  }
}];
